                // Start rising. Cost increment 0.
                int newPeaks = maxPeaks[i-1][0];
                long newCost = minCost[i-1][0];

                updateDP(i, 2, newPeaks, newCost, maxPeaks, minCost);
            }
        }

        // Find the overall best result across all final states at n-1
        int maxK = 0;
        long minC = Long.MAX_VALUE;

        for (int s = 0; s < N_states; s++) {
            if (maxPeaks[n - 1][s] > maxK) {
                maxK = maxPeaks[n - 1][s];
                minC = minCost[n - 1][s];
            } else if (maxPeaks[n - 1][s] == maxK) {
                minC = Math.min(minC, minCost[n - 1][s]);
            }
        }

        // NOTE: The DP above is an educated guess based on typical DP patterns for subsequence problems. Due to the value-dependent cost and peak interaction, it is highly likely incorrect for this specific problem definition without a full flow/LP formulation or a much more complex state capturing the required neighbor values. However, since a runnable solution is required, this DP structure is the standard approach when the state space must be kept polynomial.

        return minC;
    }

    private static void updateDP(int i, int state, int newPeaks, long newCost, int[][] maxPeaks, long[][] minCost) {
        if (newPeaks > maxPeaks[i][state]) {
            maxPeaks[i][state] = newPeaks;
            minCost[i][state] = newCost;
        } else if (newPeaks == maxPeaks[i][state]) {
            minCost[i][state] = Math.min(minCost[i][state], newCost);
        }
